// PATCH /api/reconcile/record/:id  - manual correction + audit logging
router.patch(
  "/record/:id",
  authMiddleware(["admin", "analyst"]),
  async (req, res) => {
    try {
      const recordId = req.params.id;
      const updates = req.body?.updates || {}; // object of fields to update
      const changedBy = req.body?.changedBy || req.user?.email || req.user?.name || "Unknown";

      // Find existing record
      const existing = await ReconciliationResult.findById(recordId);
      if (!existing) return res.status(404).json({ message: "Record not found" });

      // Prepare oldValue for audit
      const oldValue = {};
      for (const k of Object.keys(updates)) {
        oldValue[k] = existing[k];
      }

      // Perform update (only allowed fields) — whitelist fields
      const allowed = ["uploadedRecordId", "systemRecordId", "status", "differences"];
      const apply = {};
      Object.keys(updates).forEach((k) => {
        if (allowed.includes(k)) apply[k] = updates[k];
      });

      const updated = await ReconciliationResult.findByIdAndUpdate(
        recordId,
        { $set: apply },
        { new: true }
      );

      // Create audit entry
      await AuditTrail.create({
        recordId,
        action: "Manual Correction",
        changedBy,
        oldValue,
        newValue: apply,
      });

      return res.json({ message: "Record updated", record: updated });
    } catch (err) {
      console.error("Record update error:", err);
      return res.status(500).json({ message: "Failed to update record", error: err.message });
    }
  }
);
